```c
#include <stdio.h>

int main() {
    int a, y, z, result;

    // Read the first integer from input
    printf("Enter the first number: ");
    scanf("%d", &a);

    // Read second integer
    printf("\nEnter the second number: ");
   scanf("%d",&y);

    //Read third integer
   printf("\nEnter the third number: ");
     scanf("%d &= z);

    // Calculate result: a - y - z
    result = a - y;
    result = result - z;

    // Print the formatted result
    printf("%d - % d - %d= %d\n", a, y,z,result);

    return 0;
}
